15	  layer: Layer
16	  activePrimary: string | null
17	  activeSecondary: string | null
18	  visibleCounts: { total: number; released: number; dev: number; none: number }
19	  totals: { total: number }
20	  statusFilter: "all" | McpStatus
21	  viewMode: "panorama" | "list"
22	  search: string
23	  groups: Group[]
24	}>()
25	
26	const emit = defineEmits<{
27	  "update:statusFilter": ["all" | McpStatus]
28	  "update:viewMode": ["panorama" | "list"]
29	  "update:search": [string]
30	  clearDrill: []
31	}>()
32	
33	const { locale, t } = useI18n()
34	
35	const layerLabel = computed(() => t(`mcpPanorama.layer.${props.layer}`))
36	
37	const titleAndCrumb = computed<{ title: string; crumb: string | null }>(() => {
38	  if (!props.activePrimary) {
39	    return { title: t("mcpPanorama.layer." + props.layer), crumb: null }
40	  }
41	  const primary = props.groups.find((g) => g.key === props.activePrimary)
42	  if (!primary) return { title: props.activePrimary, crumb: layerLabel.value }
43	  if (props.layer === "industry") {
44	    return {
45	      title: groupDisplayTitle(primary, locale.value),
46	      crumb: layerLabel.value,
47	    }
48	  }
49	  if (primary.kind !== "domain") {
50	    return { title: groupDisplayTitle(primary, locale.value), crumb: layerLabel.value }
51	  }
52	  if (props.activeSecondary) {
53	    const pdt = primary.pdts.find((p) => p.key === props.activeSecondary) as PdtBlock | undefined
54	    if (pdt) {
55	      return {
56	        title: pdtDisplayTitle(pdt, locale.value),
57	        crumb: `${layerLabel.value} / ${groupDisplayTitle(primary, locale.value)}`,
58	      }
59	    }
60	  }
61	  return {
62	    title: groupDisplayTitle(primary, locale.value),
63	    crumb: layerLabel.value,
64	  }
65	})
66	
67	const subtitle = computed(() => {
68	  if (!props.activePrimary) {
69	    return t("mcpPanorama.page.subtitleAll", {
70	      visible: props.visibleCounts.total,
71	      total: props.totals.total,
72	    })
73	  }
74	  return t("mcpPanorama.page.subtitleScoped", {
75	    visible: props.visibleCounts.total,
76	    released: props.visibleCounts.released,
77	    dev: props.visibleCounts.dev,
78	    none: props.visibleCounts.none,
79	  })
80	})
81	
82	function statusLabel(s: McpStatus): string {
83	  return t(`mcpPanorama.status.${s}.label`)
84	}
85	
86	const localSearch = computed({
87	  get: () => props.search,
88	  set: (v: string) => emit("update:search", v),
89	})
90	</script>
91	
92	<template>
